#' Table Summary
#'
#' 
#' @param data .
#' @param varsCont .
#' @param varsCat .
#' @param groupBy .
#' @param missing .
#' @param missingText .
#' @param percent .
#' @param journal .
#' @param compact .
#' @param language .
#' @param statContDefault .
#' @param statsContSpecific .
#' @param statCatDefault .
#' @param statsCatSpecific .
#' @param pValue .
#' @param testContDefault .
#' @param testsContSpecific .
#' @param testCatDefault .
#' @param testsCatSpecific .
#' @param export .
#' @param path .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$tbl} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' @export
tblSummary <- function(
    data,
    varsCont,
    varsCat,
    groupBy,
    missing = "ifany",
    missingText = "Unknown",
    percent = "column",
    journal = "none",
    compact = FALSE,
    language = "en",
    statContDefault = "mean_sd",
    statsContSpecific,
    statCatDefault = "n_percent",
    statsCatSpecific,
    pValue = FALSE,
    testContDefault = "parametric",
    testsContSpecific = list(),
    testCatDefault = "auto",
    testsCatSpecific = list(),
    export = FALSE,
    path = "~/Desktop/summary_table.docx") {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("tblSummary requires jmvcore to be installed (restart may be required)")

    if ( ! missing(varsCont)) varsCont <- jmvcore::resolveQuo(jmvcore::enquo(varsCont))
    if ( ! missing(varsCat)) varsCat <- jmvcore::resolveQuo(jmvcore::enquo(varsCat))
    if ( ! missing(groupBy)) groupBy <- jmvcore::resolveQuo(jmvcore::enquo(groupBy))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(varsCont), varsCont, NULL),
            `if`( ! missing(varsCat), varsCat, NULL),
            `if`( ! missing(groupBy), groupBy, NULL))


    options <- tblSummaryOptions$new(
        varsCont = varsCont,
        varsCat = varsCat,
        groupBy = groupBy,
        missing = missing,
        missingText = missingText,
        percent = percent,
        journal = journal,
        compact = compact,
        language = language,
        statContDefault = statContDefault,
        statsContSpecific = statsContSpecific,
        statCatDefault = statCatDefault,
        statsCatSpecific = statsCatSpecific,
        pValue = pValue,
        testContDefault = testContDefault,
        testsContSpecific = testsContSpecific,
        testCatDefault = testCatDefault,
        testsCatSpecific = testsCatSpecific,
        export = export,
        path = path)

    analysis <- tblSummaryClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

